#include <stdio.h>
#include <stdlib.h>
#define MAX 100001
int n, m;
typedef struct Node {
    int val;
    struct Node* next;
} Node;
Node* adj[MAX];
void addEdge(int u, int v) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->val = v;
    newNode->next = adj[u];
    adj[u] = newNode;
}
int dfs(int u, int v, int* visited) {
    if (u == v) return 0;
    visited[u] = 1;
    Node* temp = adj[u];
    int min = -1;
    while (temp) {
        if (!visited[temp->val]) {
            int dist = dfs(temp->val, v, visited);
            if (dist != -1) {
                if (min == -1 || dist + 1 < min) min = dist + 1;
            }
        }
        temp = temp->next;
    }
    return min;
}
int main() {
    scanf("%d", &n);
    for (int i = 0; i < n - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addEdge(u, v);
        addEdge(v, u);
    }
    scanf("%d", &m);
    for (int i = 0; i < m; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        int* visited = (int*) calloc(n + 1, sizeof(int));
        printf("%d\n", dfs(u, v, visited));
        free(visited);
    }
    return 0;
}

