import java.util.ArrayList;
import java.util.Scanner;
public class Main {
    static final int MAX = 100001;
    static ArrayList<Integer>[] adj = new ArrayList[MAX];
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        for (int i = 0; i < MAX; i++) adj[i] = new ArrayList<>();
        for (int i = 0; i < n - 1; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            adj[u].add(v);
            adj[v].add(u);
        }
        int m = scanner.nextInt();
        for (int i = 0; i < m; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            boolean[] visited = new boolean[n + 1];
            System.out.println(dfs(u, v, visited));
        }
    }
    public static int dfs(int u, int v, boolean[] visited) {
        if (u == v) return 0;
        visited[u] = true;
        int min = -1;
        for (int i = 0; i < adj[u].size(); i++) {
            if (!visited[adj[u].get(i)]) {
                int dist = dfs(adj[u].get(i), v, visited);
                if (dist != -1) {
                    if (min == -1 || dist + 1 < min) min = dist + 1;
                }
            }
        }
        return min;
    }
}

