    function dfs(adj, u, v, visited) {
        if (u == v) return 0;
        visited[u] = true;
        let min = Infinity;
        for (let neighbor of adj[u]) {
            if (!visited[neighbor]) {
                let dist = dfs(adj, neighbor, v, visited);
                if (dist != -1) {
                    min = Math.min(min, dist + 1);
                }
            }
        }
        return min == Infinity ? -1 : min;
    }
